export type Cell = [number, number];

const coordKey = ([x, y]: Cell): string => `${x},${y}`;

type NeighborEntry = { cell: Cell; count: number };

export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
  const live = new Set(liveCells.map(coordKey));
  const neighbors = new Map<string, NeighborEntry>();

  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const cell: Cell = [x + dx, y + dy];
        const k = coordKey(cell);
        const entry = neighbors.get(k) ?? { cell, count: 0 };
        entry.count++;
        neighbors.set(k, entry);
      }
    }
  }

  const survives = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && live.has(k));

  return [...neighbors]
    .filter(([k, { count }]) => survives(k, count))
    .map(([, { cell }]) => cell);
}
